#include "ctl_main.h"

buck_ctrl_t buck_ctrl;
ptr_adc_channel_t adc_channel;
pwm_channel_t pwm_channel;
std_vip_protection_t protection;
ctl_trip_protector_t trip_protector;
std_interface_t std_interface;

static void apply_tunable_params(void);

void ctl_init(void)
{
    ctl_init_buck_ctrl(&buck_ctrl);
    ctl_init_ptr_adc_channel(&adc_channel);
    ctl_init_pwm_channel(&pwm_channel);
    ctl_init_vip_protection(&protection);
    ctl_init_trip_protector(&trip_protector);
    ctl_init_std_interface(&std_interface);

    ctl_attach_buck_ctrl_input(&buck_ctrl, &adc_channel.control_port, &adc_channel.control_port, &adc_channel.control_port);
    ctl_attach_vip_protection(&protection, &adc_channel.control_port, &adc_channel.control_port);

    apply_tunable_params();

    ctl_enable_pwm();
}

void ctl_mainloop(void)
{
    ctl_step_ptr_adc_channel(&adc_channel);

    ctl_dispatch_fast_loop();

    ctl_step_pwm_channel(&pwm_channel, buck_ctrl.voltage_pid.output);

    ctl_dispatch_fault();
}

void clear_all_controllers(void)
{
    ctl_clear_buck_ctrl(&buck_ctrl);
    ctl_clear_vip_protection(&protection);
    ctl_clear_trip_protector(&trip_protector);
}

void tsk_protect(void)
{
    ctl_step_trip_protector(&trip_protector);
}

void ctl_enable_pwm(void)
{
    pwm_channel.enable = 1;
}

void ctl_disable_pwm(void)
{
    pwm_channel.enable = 0;
}

static void apply_tunable_params(void)
{
    buck_ctrl.voltage_pid.kp = 0.5f;
    buck_ctrl.voltage_pid.ki = 0.1f;
    buck_ctrl.voltage_pid.kd = 0.01f;

    protection.voltage_max = 48.0f;
    protection.current_max = 10.0f;
    protection.power_max = 240.0f;

    trip_protector.warning_threshold = 0.8f;
    trip_protector.trip_threshold = 1.0f;
    trip_protector.fault_threshold = 1.2f;
}
